/* ============================================
   Nitfix Design System - CSS 鍙橀噺瀹氫箟
   鍩轰簬 Netflix 椋庢牸浼樺寲鐨勫奖瑙嗘捣鎶ュ璁捐绯荤粺
   ============================================ */
:root {
  /* === 鑹插僵绯荤粺 === */
  /* 涓昏儗鏅壊 - 娣遍們榛戣壊绯?*/
  --color-bg-primary: #0a0a0a;
  --color-bg-secondary: #141414;
  --color-bg-tertiary: #1f1f1f;
  --color-bg-elevated: #2a2a2a;
  --color-bg-card: #181818;

  /* Nitfix 鍝佺墝鑹?- 娲诲姏绾㈣壊 */
  --color-brand-primary: #e50914;
  --color-brand-secondary: #b20710;
  --color-brand-light: #ff1a1a;
  --color-brand-gradient: linear-gradient(135deg, #e50914 0%, #b20710 100%);

  /* 鏂囧瓧棰滆壊 */
  --color-text-primary: #ffffff;
  --color-text-secondary: #a3a3a3;
  --color-text-tertiary: #737373;
  --color-text-muted: #525252;

  /* 鍔熻兘鑹?*/
  --color-success: #22c55e;
  --color-success-dark: #16a34a;
  --color-warning: #f59e0b;
  --color-warning-dark: #d97706;
  --color-error: #ef4444;
  --color-error-dark: #dc2626;
  --color-info: #3b82f6;
  --color-info-dark: #2563eb;

  /* 杈规棰滆壊 */
  --color-border-default: rgba(255, 255, 255, 0.08);
  --color-border-subtle: rgba(255, 255, 255, 0.04);
  --color-border-strong: rgba(255, 255, 255, 0.15);
  --color-border-hover: rgba(229, 9, 20, 0.4);

  /* 閬僵灞?*/
  --color-overlay-light: rgba(0, 0, 0, 0.3);
  --color-overlay-medium: rgba(0, 0, 0, 0.6);
  --color-overlay-dark: rgba(0, 0, 0, 0.85);
  --color-overlay-gradient: linear-gradient(180deg, transparent 0%, rgba(0,0,0,0.8) 100%);

  /* === 鎺掔増绯荤粺 === */
  /* 瀛椾綋鏃?- 浣跨敤绯荤粺瀛椾綋鏍堢‘淇濇€ц兘 */
  --font-family-primary: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  --font-family-display: "Netflix Sans", "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-family-mono: "SF Mono", Monaco, "Cascadia Code", "Roboto Mono", monospace;

  /* 瀛椾綋澶у皬 - 浣跨敤 rem 鍗曚綅 */
  --font-size-xs: 0.75rem;    /* 12px */
  --font-size-sm: 0.875rem;   /* 14px */
  --font-size-base: 1rem;     /* 16px */
  --font-size-lg: 1.125rem;   /* 18px */
  --font-size-xl: 1.25rem;    /* 20px */
  --font-size-2xl: 1.5rem;    /* 24px */
  --font-size-3xl: 2rem;      /* 32px */
  --font-size-4xl: 2.5rem;    /* 40px */
  --font-size-5xl: 3rem;      /* 48px */

  /* 瀛楅噸 */
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-extrabold: 800;

  /* 琛岄珮 */
  --line-height-tight: 1.2;
  --line-height-snug: 1.35;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.625;
  --line-height-loose: 1.75;

  /* 瀛楅棿璺?*/
  --letter-spacing-tight: -0.02em;
  --letter-spacing-normal: 0;
  --letter-spacing-wide: 0.02em;
  --letter-spacing-wider: 0.05em;

  /* === 闂磋窛绯荤粺 - 8px 鍩哄噯 === */
  --spacing-0: 0;
  --spacing-1: 0.25rem;   /* 4px */
  --spacing-2: 0.5rem;    /* 8px */
  --spacing-3: 0.75rem;   /* 12px */
  --spacing-4: 1rem;      /* 16px */
  --spacing-5: 1.25rem;   /* 20px */
  --spacing-6: 1.5rem;    /* 24px */
  --spacing-8: 2rem;      /* 32px */
  --spacing-10: 2.5rem;   /* 40px */
  --spacing-12: 3rem;     /* 48px */
  --spacing-16: 4rem;     /* 64px */
  --spacing-20: 5rem;     /* 80px */
  --spacing-24: 6rem;     /* 96px */

  /* 鍝嶅簲寮忛棿璺?*/
  --gutter-mobile: var(--spacing-3);
  --gutter-tablet: var(--spacing-4);
  --gutter-desktop: var(--spacing-6);

  /* === 鍦嗚绯荤粺 === */
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-lg: 8px;
  --radius-xl: 12px;
  --radius-2xl: 16px;
  --radius-3xl: 24px;
  --radius-full: 9999px;

  /* === 闃村奖绯荤粺 === */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 6px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 8px 16px rgba(0, 0, 0, 0.5);
  --shadow-xl: 0 12px 32px rgba(0, 0, 0, 0.6);
  --shadow-2xl: 0 20px 48px rgba(0, 0, 0, 0.7);
  --shadow-glow-red: 0 0 20px rgba(229, 9, 20, 0.4);
  --shadow-glow-success: 0 0 20px rgba(34, 197, 94, 0.4);

  /* === 杩囨浮鍔ㄧ敾 === */
  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slower: 400ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-transform: 200ms cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --transition-scale: 250ms cubic-bezier(0.34, 1.56, 0.64, 1);

  /* === 灞傜骇绯荤粺 === */
  --z-index-dropdown: 50;
  --z-index-sticky: 100;
  --z-index-fixed: 200;
  --z-index-modal-backdrop: 300;
  --z-index-modal: 400;
  --z-index-popover: 500;
  --z-index-tooltip: 600;
  --z-index-toast: 700;

  /* === 鍝嶅簲寮忔柇鐐?=== */
  --breakpoint-sm: 640px;
  --breakpoint-md: 768px;
  --breakpoint-lg: 1024px;
  --breakpoint-xl: 1280px;
  --breakpoint-2xl: 1536px;

  /* === 瀹瑰櫒瀹藉害 === */
  --container-sm: 640px;
  --container-md: 768px;
  --container-lg: 1024px;
  --container-xl: 1280px;
  --container-2xl: 1536px;

  /* === 鍏煎鏃у彉閲?=== */
  --bg: var(--color-bg-primary);
  --text: var(--color-text-primary);
  --text-sub: var(--color-text-secondary);
  --netflix-red: var(--color-brand-primary);
}

/* ============================================
   鍩虹閲嶇疆涓庡叏灞€鏍峰紡
   ============================================ */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  background: var(--color-bg-primary);
  color: var(--color-text-primary);
  font-family: var(--font-family-primary);
  font-size: var(--font-size-base);
  font-weight: var(--font-weight-normal);
  line-height: var(--line-height-normal);
  text-rendering: optimizeLegibility;
  overflow-x: hidden;
  min-height: 100vh;
}

/* === 閾炬帴鏍峰紡 === */
a {
  color: inherit;
  text-decoration: none;
  transition: color var(--transition-fast);
}

a:hover {
  color: var(--color-text-secondary);
}

a:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

/* === 鍥剧墖浼樺寲 === */
img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* === 鎸夐挳閲嶇疆 === */
button {
  font-family: inherit;
  font-size: inherit;
  cursor: pointer;
  border: none;
  background: transparent;
}

button:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

/* === 杈撳叆妗嗛噸缃?=== */
input,
textarea,
select {
  font-family: inherit;
  font-size: inherit;
  color: inherit;
}

/* ============================================
   甯冨眬瀹瑰櫒
   ============================================ */
.shell {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-4);
  padding: var(--spacing-4);
  max-width: var(--container-2xl);
  margin: 0 auto;
}

@media (min-width: 768px) {
  .shell {
    padding: var(--spacing-4) var(--spacing-6);
  }
}

@media (min-width: 1280px) {
  .shell {
    padding: var(--spacing-5) var(--spacing-12);
  }
}

/* ============================================
   绔欑偣澶撮儴瀵艰埅
   ============================================ */
.site-header {
  position: sticky;
  top: 0;
  z-index: var(--z-index-sticky);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  background: rgba(10, 10, 10, 0.7);
  border-bottom: 1px solid transparent;
  transition: all var(--transition-slow);
}

.site-header::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(0,0,0,0.5) 0%, transparent 100%);
  pointer-events: none;
  transition: opacity var(--transition-slow);
}

.site-header.scrolled {
  background: rgba(20, 20, 20, 0.95);
  backdrop-filter: blur(30px);
  -webkit-backdrop-filter: blur(30px);
  border-bottom: 1px solid var(--color-border-subtle);
}

.site-header.scrolled::before {
  opacity: 0;
}

/* 鍝佺墝鍖哄煙 */
.brand-area {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  position: relative;
  z-index: 1;
}

.home-link {
  font-weight: var(--font-weight-extrabold);
  font-size: var(--font-size-xl);
  letter-spacing: var(--letter-spacing-tight);
  color: var(--color-brand-primary);
  text-decoration: none;
  transition: all var(--transition-fast);
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.home-link::before {
  content: '鈻?;
  font-size: var(--font-size-lg);
  color: var(--color-brand-primary);
}

.home-link:hover {
  color: var(--color-brand-light);
  transform: scale(1.02);
}

/* 鎼滅储缁勪欢 */
.search {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  flex: 1;
  max-width: 500px;
  position: relative;
  z-index: 1;
}

.search input {
  background: var(--color-bg-secondary);
  border: 1px solid var(--color-border-default);
  color: var(--color-text-primary);
  padding: var(--spacing-2) var(--spacing-4);
  border-radius: var(--radius-full);
  min-width: 0;
  flex: 1;
  font-size: var(--font-size-sm);
  transition: all var(--transition-fast);
}

.search input::placeholder {
  color: var(--color-text-tertiary);
}

.search input:hover {
  border-color: var(--color-border-strong);
  background: var(--color-bg-tertiary);
}

.search input:focus {
  outline: none;
  border-color: var(--color-brand-primary);
  box-shadow: 0 0 0 3px rgba(229, 9, 20, 0.15);
  background: var(--color-bg-tertiary);
}

.search button {
  background: var(--color-brand-gradient);
  color: var(--color-text-primary);
  border: none;
  border-radius: var(--radius-full);
  padding: var(--spacing-2) var(--spacing-5);
  font-weight: var(--font-weight-semibold);
  font-size: var(--font-size-sm);
  cursor: pointer;
  transition: all var(--transition-fast);
  white-space: nowrap;
}

.search button:hover {
  background: linear-gradient(135deg, #ff1a1a 0%, #e50914 100%);
  transform: translateY(-1px);
  box-shadow: var(--shadow-glow-red);
}

.search button:active {
  transform: scale(0.96);
}

/* ============================================
   椤甸潰涓讳綋甯冨眬
   ============================================ */
.page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-16);
  padding: var(--spacing-6) 0 var(--spacing-20);
}

.section {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-3);
}

/* ============================================
   Hero Section - 棣栭〉绮鹃€夊睍绀?
   ============================================ */
.hero-section {
  position: relative;
  width: 100%;
  min-height: 70vh;
  max-height: 85vh;
  display: flex;
  align-items: flex-end;
  margin-top: calc(-1 * var(--spacing-6));
  margin-bottom: var(--spacing-4);
  overflow: hidden;
}

.hero-background {
  position: absolute;
  inset: 0;
  z-index: 0;
}

.hero-background img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center center;
}

.hero-gradient {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    180deg,
    rgba(10, 10, 10, 0.3) 0%,
    rgba(10, 10, 10, 0.5) 40%,
    rgba(10, 10, 10, 0.95) 80%,
    var(--color-bg-primary) 100%
  );
}

.hero-vignette {
  position: absolute;
  inset: 0;
  background: radial-gradient(
    ellipse at center,
    transparent 0%,
    rgba(0, 0, 0, 0.4) 100%
  );
}

.hero-content {
  position: relative;
  z-index: 1;
  max-width: 45%;
  padding: var(--spacing-6) var(--spacing-4) var(--spacing-10);
  margin-left: 0;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-1) var(--spacing-3);
  background: linear-gradient(135deg, #46D369 0%, #2eb85c 100%);
  border-radius: var(--radius-sm);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-bold);
  color: var(--color-bg-primary);
  margin-bottom: var(--spacing-4);
  text-transform: uppercase;
  letter-spacing: var(--letter-spacing-wider);
}

.hero-title {
  margin: 0 0 var(--spacing-3) 0;
  font-size: clamp(var(--font-size-3xl), 5vw, var(--font-size-5xl));
  font-weight: var(--font-weight-extrabold);
  letter-spacing: var(--letter-spacing-tight);
  line-height: var(--line-height-tight);
  text-shadow: 0 4px 12px rgba(0, 0, 0, 0.6);
}

.hero-meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-3);
  margin-bottom: var(--spacing-4);
  font-size: var(--font-size-sm);
  color: var(--color-text-secondary);
}

.hero-meta-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
}

.hero-meta-item.rating {
  color: var(--color-warning);
  font-weight: var(--font-weight-bold);
}

.hero-meta-divider {
  width: 4px;
  height: 4px;
  border-radius: var(--radius-full);
  background: var(--color-text-muted);
}

.hero-overview {
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: var(--spacing-5);
  font-size: var(--font-size-base);
  line-height: var(--line-height-relaxed);
  color: var(--color-text-secondary);
  max-width: 600px;
}

.hero-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-2);
  margin-bottom: var(--spacing-5);
}

.hero-tag {
  padding: var(--spacing-1) var(--spacing-3);
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid var(--color-border-default);
  border-radius: var(--radius-full);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
  transition: all var(--transition-fast);
}

.hero-tag:hover {
  background: rgba(255, 255, 255, 0.12);
  border-color: var(--color-border-strong);
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-3);
}

.hero-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-2);
  padding: var(--spacing-3) var(--spacing-6);
  border-radius: var(--radius-full);
  font-size: var(--font-size-base);
  font-weight: var(--font-weight-semibold);
  cursor: pointer;
  transition: all var(--transition-fast);
  text-decoration: none;
  border: none;
}

.hero-btn-primary {
  background: var(--color-text-primary);
  color: var(--color-bg-primary);
}

.hero-btn-primary:hover {
  background: rgba(255, 255, 255, 0.85);
  transform: scale(1.02);
}

.hero-btn-primary:active {
  transform: scale(0.98);
}

.hero-btn-secondary {
  background: rgba(109, 109, 110, 0.7);
  color: var(--color-text-primary);
}

.hero-btn-secondary:hover {
  background: rgba(109, 109, 110, 0.5);
  transform: scale(1.02);
}

.hero-btn-secondary:active {
  transform: scale(0.98);
}

.hero-btn-icon {
  font-size: var(--font-size-lg);
}

/* Hero 鍝嶅簲寮?*/
@media (max-width: 767px) {
  .hero-section {
    min-height: 60vh;
    max-height: 75vh;
  }

  .hero-content {
    max-width: 100%;
    padding: var(--spacing-4) var(--spacing-4) var(--spacing-8);
  }

  .hero-title {
    font-size: var(--font-size-2xl);
  }

  .hero-overview {
    -webkit-line-clamp: 2;
    font-size: var(--font-size-sm);
  }

  .hero-actions {
    flex-direction: column;
  }

  .hero-btn {
    width: 100%;
    justify-content: center;
  }
}

@media (min-width: 768px) {
  .hero-content {
    padding: var(--spacing-8) var(--spacing-6) var(--spacing-12);
  }
}

@media (min-width: 1280px) {
  .hero-content {
    padding: var(--spacing-10) var(--spacing-12) var(--spacing-16);
  }

  .hero-title {
    font-size: var(--font-size-5xl);
  }
}

/* 鍖哄潡澶撮儴 */
.section-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  padding: 0 var(--spacing-4);
}

.section-icon {
  color: var(--color-brand-primary);
  font-size: var(--font-size-xl);
  filter: drop-shadow(0 0 8px rgba(229, 9, 20, 0.4));
}

.section-title {
  margin: 0;
  font-weight: var(--font-weight-bold);
  font-size: var(--font-size-xl);
  letter-spacing: var(--letter-spacing-tight);
  color: var(--color-text-primary);
}

/* 楂樹寒鍖哄潡鏍峰紡 */
.section-highlight {
  background: linear-gradient(180deg, rgba(229, 9, 20, 0.05) 0%, transparent 100%);
  padding-top: var(--spacing-4);
  margin-top: var(--spacing-2);
}

.section-header-highlight {
  background: linear-gradient(90deg, rgba(229, 9, 20, 0.1) 0%, transparent 100%);
  padding: var(--spacing-3) var(--spacing-4);
  border-radius: var(--radius-lg);
  border-left: 3px solid var(--color-brand-primary);
}

.section-badge {
  display: inline-flex;
  align-items: center;
  padding: var(--spacing-1) var(--spacing-3);
  border-radius: var(--radius-full);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-bold);
  text-transform: uppercase;
  letter-spacing: var(--letter-spacing-wide);
  margin-left: auto;
  animation: pulse 2s ease-in-out infinite;
}

.anime-badge {
  background: linear-gradient(135deg, #ff6b9d 0%, #c44569 100%);
  color: var(--color-text-primary);
  box-shadow: 0 0 12px rgba(255, 107, 157, 0.4);
}

.china-badge {
  background: linear-gradient(135deg, #f39c12 0%, #e74c3c 100%);
  color: var(--color-text-primary);
  box-shadow: 0 0 12px rgba(243, 156, 18, 0.4);
}

/* 鍔ㄦ极鍖哄潡鐗规畩鏍峰紡 */
.posters-grid-anime .poster-card {
  position: relative;
}

.posters-grid-anime .poster-card::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: var(--radius-xl);
  pointer-events: none;
  box-shadow: inset 0 0 0 1px rgba(255, 107, 157, 0.2);
  transition: box-shadow var(--transition-fast);
}

.posters-grid-anime .poster-card:hover::after {
  box-shadow: inset 0 0 0 2px rgba(255, 107, 157, 0.5);
}

@media (min-width: 768px) {
  .section-header {
    padding: 0 var(--spacing-6);
  }
  .section-title {
    font-size: var(--font-size-2xl);
  }
}

@media (min-width: 1280px) {
  .section-header {
    padding: 0 var(--spacing-12);
  }
  .section-title {
    font-size: var(--font-size-3xl);
  }
}

/* ============================================
   娴锋姤鍗＄墖缃戞牸绯荤粺
   ============================================ */
.posters-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--gutter-mobile);
  padding: 0 var(--spacing-4);
}

/* 妯悜婊氬姩瀹瑰櫒 - 鍩虹鏍峰紡锛屼緵 ScrollableRow 缁勪欢浣跨敤 */
.posters-row,
:deep(.scrollable-row-container) {
  display: flex;
  overflow-x: auto;
  gap: var(--spacing-3);
  padding: var(--spacing-2) var(--spacing-4);
  scroll-behavior: smooth;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

.posters-row::-webkit-scrollbar,
:deep(.scrollable-row-container)::-webkit-scrollbar {
  display: none;
}

.posters-row .poster-card,
:deep(.scrollable-row-container) .poster-card {
  flex-shrink: 0;
  width: calc(50% - var(--spacing-2));
}

.posters-row.is-dragging,
:deep(.scrollable-row-container.is-dragging) {
  scroll-behavior: auto;
  cursor: grabbing;
}

.posters-row.is-dragging .poster-card,
:deep(.scrollable-row-container.is-dragging) .poster-card {
  pointer-events: none;
}

/* 婊氬姩鎸囩ず…9765 tokens truncated…dges {
  display: flex;
  gap: var(--spacing-2);
  flex-shrink: 0;
}

.badge-best {
  padding: 2px var(--spacing-2);
  background: linear-gradient(135deg, var(--color-warning) 0%, var(--color-warning-dark) 100%);
  color: var(--color-bg-primary);
  border-radius: var(--radius-sm);
  font-size: 10px;
  font-weight: var(--font-weight-bold);
}

.badge-quality {
  padding: 2px var(--spacing-2);
  background: rgba(255, 255, 255, 0.08);
  color: var(--color-text-primary);
  border-radius: var(--radius-sm);
  font-size: 10px;
  font-weight: var(--font-weight-semibold);
}

.resource-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-2);
}

.resource-tag {
  padding: 2px var(--spacing-2);
  background: rgba(229, 9, 20, 0.1);
  color: var(--color-brand-primary);
  border-radius: var(--radius-sm);
  font-size: 10px;
  font-weight: var(--font-weight-semibold);
}

.resource-score {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-2) var(--spacing-3);
  background: rgba(255, 255, 255, 0.03);
  border-radius: var(--radius-lg);
}

.score-label {
  font-size: var(--font-size-xs);
  color: var(--color-text-secondary);
}

.score-value {
  font-size: var(--font-size-lg);
  font-weight: var(--font-weight-extrabold);
  color: var(--color-success);
}

.resource-actions {
  display: flex;
  gap: var(--spacing-2);
}

.resource-actions .btn {
  flex: 1;
  padding: var(--spacing-2) var(--spacing-3);
  font-size: var(--font-size-xs);
}

.resource-status {
  font-size: var(--font-size-xs);
  text-align: center;
  min-height: 20px;
}

/* ============================================
   鍔ㄧ敾鍏抽敭甯?
   ============================================ */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeOutDown {
  from {
    opacity: 1;
    transform: translateY(0);
  }
  to {
    opacity: 0;
    transform: translateY(16px);
  }
}

@keyframes pulse {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.6;
  }
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* 椤甸潰鍏ュ満鍔ㄧ敾 */
.animate-in {
  animation: fadeInUp 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
  opacity: 0;
}

.section {
  animation: fadeInUp 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
  opacity: 0;
}

.section:nth-child(1) { animation-delay: 0.05s; }
.section:nth-child(2) { animation-delay: 0.1s; }
.section:nth-child(3) { animation-delay: 0.15s; }
.section:nth-child(4) { animation-delay: 0.2s; }
.section:nth-child(5) { animation-delay: 0.25s; }
.section:nth-child(6) { animation-delay: 0.3s; }

/* 娴锋姤鍗＄墖 stagger 鍔ㄧ敾 */
.posters-grid .poster-card {
  animation: fadeInUp 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
  opacity: 0;
}

.posters-grid .poster-card:nth-child(1) { animation-delay: 0.05s; }
.posters-grid .poster-card:nth-child(2) { animation-delay: 0.1s; }
.posters-grid .poster-card:nth-child(3) { animation-delay: 0.15s; }
.posters-grid .poster-card:nth-child(4) { animation-delay: 0.2s; }
.posters-grid .poster-card:nth-child(5) { animation-delay: 0.25s; }
.posters-grid .poster-card:nth-child(6) { animation-delay: 0.3s; }
.posters-grid .poster-card:nth-child(7) { animation-delay: 0.35s; }
.posters-grid .poster-card:nth-child(8) { animation-delay: 0.4s; }
.posters-grid .poster-card:nth-child(9) { animation-delay: 0.45s; }
.posters-grid .poster-card:nth-child(10) { animation-delay: 0.5s; }
.posters-grid .poster-card:nth-child(n+11) { animation-delay: 0.55s; }

/* ============================================
   Toast 鎻愮ず鏍峰紡
   ============================================ */
.toast {
  animation: fadeInUp 0.3s ease;
}

.toast-success {
  background: linear-gradient(135deg, var(--color-success) 0%, var(--color-success-dark) 100%);
  color: var(--color-text-primary);
}

.toast-error {
  background: linear-gradient(135deg, var(--color-error) 0%, var(--color-error-dark) 100%);
  color: var(--color-text-primary);
}

.toast-info {
  background: rgba(20, 20, 20, 0.95);
  color: var(--color-text-primary);
  border: 1px solid var(--color-border-default);
  backdrop-filter: blur(10px);
}

/* ============================================
   閲嶅懡鍚嶆棩蹇楁ā鎬佹
   ============================================ */
.rename-log-modal {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-4);
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  z-index: var(--z-index-modal);
}

.rename-log-dialog {
  width: min(900px, 100%);
  max-height: 88vh;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-4);
  background: linear-gradient(160deg, rgba(24, 24, 24, 0.98) 0%, rgba(16, 16, 16, 0.98) 100%);
  border: 1px solid var(--color-border-default);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-2xl);
  padding: var(--spacing-5);
}

.rename-log-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-3);
}

.rename-log-title {
  margin: 0;
  font-size: var(--font-size-lg);
  font-weight: var(--font-weight-bold);
  color: var(--color-text-primary);
}

.rename-log-close {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-full);
  border: 1px solid var(--color-border-default);
  background: rgba(255, 255, 255, 0.06);
  color: var(--color-text-primary);
  font-size: 18px;
  line-height: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.rename-log-close:hover {
  background: rgba(239, 68, 68, 0.2);
  border-color: rgba(239, 68, 68, 0.4);
}

.rename-progress-wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.rename-progress-track {
  width: 100%;
  height: 10px;
  border-radius: var(--radius-full);
  background: rgba(255, 255, 255, 0.08);
  overflow: hidden;
}

.rename-progress-fill {
  width: 0%;
  height: 100%;
  background: linear-gradient(90deg, #1f9d55 0%, #3ecf8e 100%);
  transition: width var(--transition-base);
}

.rename-progress-text {
  font-size: var(--font-size-sm);
  color: var(--color-text-secondary);
}

.rename-log-lines {
  flex: 1;
  min-height: 240px;
  max-height: 52vh;
  overflow-y: auto;
  border: 1px solid var(--color-border-subtle);
  border-radius: var(--radius-lg);
  background: rgba(0, 0, 0, 0.3);
  padding: var(--spacing-3);
  font-family: var(--font-family-mono);
  font-size: 13px;
  line-height: 1.45;
}

.rename-log-line {
  margin-bottom: var(--spacing-2);
  white-space: pre-wrap;
  word-break: break-word;
}

.rename-log-line.level-info {
  color: #cbd5e1;
}

.rename-log-line.level-warning {
  color: #f59e0b;
}

.rename-log-line.level-error {
  color: #f87171;
}

.rename-log-summary {
  min-height: 24px;
  font-size: var(--font-size-sm);
  color: var(--color-text-secondary);
}

.rename-log-summary.done {
  color: #d1fae5;
}

.rename-log-summary.has-error {
  color: #fecaca;
}

.rename-log-actions {
  display: flex;
  justify-content: flex-end;
}

/* ============================================
   鍝嶅簲寮忎紭鍖?
   ============================================ */
@media (max-width: 767px) {
  .quark-resource-card {
    min-width: 260px;
    max-width: 300px;
    padding: var(--spacing-3);
  }

  .pagination {
    padding: var(--spacing-6) var(--spacing-3);
    gap: var(--spacing-3);
  }

  .btn-page {
    padding: var(--spacing-2) var(--spacing-4);
    font-size: var(--font-size-sm);
  }

  .page {
    padding-bottom: 100px;
  }

  .search {
    max-width: none;
  }

  .search input {
    min-width: 0;
  }

  .home-link {
    font-size: var(--font-size-base);
  }

  .home-link span {
    display: none;
  }

  .rename-log-dialog {
    max-height: 94vh;
    padding: var(--spacing-4);
  }

  .rename-log-title {
    font-size: var(--font-size-base);
  }

  .rename-log-lines {
    min-height: 200px;
    max-height: 48vh;
  }
}

@media (min-width: 768px) {
  .quark-resource-card {
    min-width: 320px;
    max-width: 380px;
  }
}

@media (min-width: 1280px) {
  .quark-resource-card {
    min-width: 340px;
    max-width: 400px;
  }
}

/* ============================================
   鍙闂€у寮?
   ============================================ */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

/* 楂樺姣斿害妯″紡鏀寔 */
@media (prefers-contrast: high) {
  :root {
    --color-border-default: rgba(255, 255, 255, 0.25);
    --color-border-subtle: rgba(255, 255, 255, 0.15);
  }

  .poster-card:hover {
    outline: 2px solid var(--color-text-primary);
  }
}

/* 鎵撳嵃鏍峰紡 */
@media print {
  .site-header,
  .main-nav,
  .pagination,
  .btn,
  .delete-btn,
  .transfer-btn,
  .rename-btn,
  .rename-log-modal {
    display: none !important;
  }

  body {
    background: white;
    color: black;
  }

  .poster-card,
  .cast-card,
  .video-card {
    break-inside: avoid;
  }
}

/* ============================================
   璁剧疆椤甸潰鏍峰紡
   ============================================ */
.settings-container {
  max-width: 800px;
  margin: 0 auto;
  padding: 0 var(--spacing-4) var(--spacing-8);
}

.settings-desc {
  color: var(--color-text-tertiary);
  margin-bottom: var(--spacing-6);
  font-size: var(--font-size-sm);
}

.settings-section {
  background: linear-gradient(135deg, var(--color-bg-secondary) 0%, var(--color-bg-tertiary) 100%);
  padding: var(--spacing-5);
