import { computed, onMounted, onUnmounted, ref, watch } from "vue";
import { useRoute, useRouter } from "vue-router";

import { searchTmdbPosters } from "@/api";
import { useToast } from "@/composables/useToast";
import type { PosterCard } from "@/types/api";

const router = useRouter();
const route = useRoute();
const { push } = useToast();

const loading = ref(false);
const posters = ref<PosterCard[]>([]);
const searchHistory = ref<string[]>([]);

const query = computed(() => String(route.query.q || "").trim());
const titleText = computed(() => (query.value ? `"${query.value}" 鐨勬悳绱㈢粨鏋渀 : "鎼滅储褰辫"));

function mediaLink(mediaType: string, id: number) {
  return `/${mediaType}/${id}`;
}

function loadSearchHistory() {
  try {
    const history = localStorage.getItem("searchHistory");
    if (history) {
      searchHistory.value = JSON.parse(history);
    }
  } catch {
    searchHistory.value = [];
  }
}

function saveToHistory(query: string) {
  if (!query) return;
  const normalized = query.trim();
  searchHistory.value = [normalized, ...searchHistory.value.filter(q => q !== normalized)].slice(0, 10);
  try {
    localStorage.setItem("searchHistory", JSON.stringify(searchHistory.value));
  } catch {
    // ignore
  }
}

function clearHistory() {
  searchHistory.value = [];
  try {
    localStorage.removeItem("searchHistory");
  } catch {
    // ignore
  }
}

function useHistory(query: string) {
  void router.push({
    path: "/search",
    query: { q: query },
  });
}

async function runSearch() {
  if (!query.value) {
    posters.value = [];
    return;
  }
  loading.value = true;
  try {
    const res = await searchTmdbPosters(query.value);
    if (res.code !== 0) {
      push(res.message || "鎼滅储澶辫触", "error");
      return;
    }
    posters.value = res.data.posters || [];
    saveToHistory(query.value);
  } catch (error) {
    push(error instanceof Error ? error.message : "鎼滅储澶辫触", "error");
  } finally {
    loading.value = false;
  }
}

watch(
  () => route.fullPath,
  () => {
    void runSearch();
  },
);

onMounted(() => {
  void runSearch();
  loadSearchHistory();
});

onUnmounted(() => {
  // cleanup if needed
});
</script>

