    setSummaryByStats(event);
    push("浠诲姟鎵ц瀹屾垚", "success");
    return;
  }

  if (type === "error") {
    const message = String(event.message || "浠诲姟澶辫触");
    appendLine("error", message);
    modalSummary.value = message;
    push(message, "error");
  }
}

function statusLabel(status: number) {
